SELECT reward_name
FROM rewards
WHERE reward_id = 1;

SELECT COUNT(*) AS redemption_count
FROM reward_redemptions
WHERE reward_id = 1;

SELECT redemption_date
FROM reward_redemptions
WHERE redemption_status = 'completed';

SELECT player_ranking_points
FROM player_rankings
WHERE player_id = 1 AND tier_id = 1;

SELECT COUNT(*) AS player_count
FROM player_rankings
WHERE tier_id = 1;

SELECT COUNT(DISTINCT reward_type) AS total_reward_types
FROM rewards
WHERE game_id = 0;

SELECT DISTINCT pr.player_id
FROM player_rankings pr
INNER JOIN reward_assignments ra ON pr.tier_id = ra.tier_id;
